  "/op-sqlite/migrator.d.ts": "import type { OPSQLiteDatabase } from \"./driver.js\";\ninterface MigrationConfig {\n    journal: {\n        entries: {\n            idx: number;\n            when: number;\n            tag: string;\n            breakpoints: boolean;\n        }[];\n    };\n    migrations: Record<string, string>;\n}\nexport declare function migrate<TSchema extends Record<string, unknown>>(db: OPSQLiteDatabase<TSchema>, config: MigrationConfig): Promise<void>;\ninterface State {\n    success: boolean;\n    error?: Error;\n}\nexport declare const useMigrations: (db: OPSQLiteDatabase<any>, migrations: {\n    journal: {\n        entries: {\n            idx: number;\n            when: number;\n            tag: string;\n            breakpoints: boolean;\n        }[];\n    };\n    migrations: Record<string, string>;\n}) => State;\nexport {};\n",
  "/op-sqlite/session.d.ts": "import type { OPSQLiteConnection, QueryResult } from '@op-engineering/op-sqlite';\nimport { entityKind } from \"../entity.js\";\nimport type { Logger } from \"../logger.js\";\nimport type { RelationalSchemaConfig, TablesRelationalConfig } from \"../relations.js\";\nimport { type Query } from \"../sql/sql.js\";\nimport type { SQLiteAsyncDialect } from \"../sqlite-core/dialect.js\";\nimport { SQLiteTransaction } from \"../sqlite-core/index.js\";\nimport type { SelectedFieldsOrdered } from \"../sqlite-core/query-builders/select.types.js\";\nimport { type PreparedQueryConfig as PreparedQueryConfigBase, type SQLiteExecuteMethod, SQLitePreparedQuery, SQLiteSession, type SQLiteTransactionConfig } from \"../sqlite-core/session.js\";\nexport interface OPSQLiteSessionOptions {\n    logger?: Logger;\n}\ntype PreparedQueryConfig = Omit<PreparedQueryConfigBase, 'statement' | 'run'>;\nexport declare class OPSQLiteSession<TFullSchema extends Record<string, unknown>, TSchema extends TablesRelationalConfig> extends SQLiteSession<'async', QueryResult, TFullSchema, TSchema> {\n    private client;\n    private schema;\n    static readonly [entityKind]: string;\n    private logger;\n    constructor(client: OPSQLiteConnection, dialect: SQLiteAsyncDialect, schema: RelationalSchemaConfig<TSchema> | undefined, options?: OPSQLiteSessionOptions);\n    prepareQuery<T extends Omit<PreparedQueryConfig, 'run'>>(query: Query, fields: SelectedFieldsOrdered | undefined, executeMethod: SQLiteExecuteMethod, isResponseInArrayMode: boolean, customResultMapper?: (rows: unknown[][]) => unknown): OPSQLitePreparedQuery<T>;\n    transaction<T>(transaction: (tx: OPSQLiteTransaction<TFullSchema, TSchema>) => T, config?: SQLiteTransactionConfig): T;\n}\nexport declare class OPSQLiteTransaction<TFullSchema extends Record<string, unknown>, TSchema extends TablesRelationalConfig> extends SQLiteTransaction<'async', QueryResult, TFullSchema, TSchema> {\n    static readonly [entityKind]: string;\n    transaction<T>(transaction: (tx: OPSQLiteTransaction<TFullSchema, TSchema>) => T): T;\n}\nexport declare class OPSQLitePreparedQuery<T extends PreparedQueryConfig = PreparedQueryConfig> extends SQLitePreparedQuery<{\n    type: 'async';\n    run: QueryResult;\n    all: T['all'];\n    get: T['get'];\n    values: T['values'];\n    execute: T['execute'];\n}> {\n    private client;\n    private logger;\n    private fields;\n    private _isResponseInArrayMode;\n    private customResultMapper?;\n    static readonly [entityKind]: string;\n    constructor(client: OPSQLiteConnection, query: Query, logger: Logger, fields: SelectedFieldsOrdered | undefined, executeMethod: SQLiteExecuteMethod, _isResponseInArrayMode: boolean, customResultMapper?: ((rows: unknown[][]) => unknown) | undefined);\n    run(placeholderValues?: Record<string, unknown>): Promise<QueryResult>;\n    all(placeholderValues?: Record<string, unknown>): Promise<T['all']>;\n    get(placeholderValues?: Record<string, unknown>): Promise<T['get']>;\n    values(placeholderValues?: Record<string, unknown>): Promise<T['values']>;\n}\nexport {};\n",
  "/operations.d.ts": "import type { AnyColumn, Column } from \"./column.js\";\nimport type { SQL } from \"./sql/sql.js\";\nimport type { Table } from \"./table.js\";\nexport type RequiredKeyOnly<TKey extends string, T extends Column> = T extends AnyColumn<{\n    notNull: true;\n    hasDefault: false;\n}> ? TKey : never;\nexport type OptionalKeyOnly<TKey extends string, T extends Column, OverrideT extends boolean | undefined = false> = TKey extends RequiredKeyOnly<TKey, T> ? never : T extends {\n    _: {\n        generated: undefined;\n    };\n} ? (T extends {\n    _: {\n        identity: undefined;\n    };\n} ? TKey : T['_']['identity'] extends 'always' ? OverrideT extends true ? TKey : never : TKey) : never;\nexport type SelectedFieldsFlat<TColumn extends Column> = Record<string, TColumn | SQL | SQL.Aliased>;\nexport type SelectedFieldsFlatFull<TColumn extends Column> = Record<string, TColumn | SQL | SQL.Aliased>;\nexport type SelectedFields<TColumn extends Column, TTable extends Table> = Record<string, SelectedFieldsFlat<TColumn>[string] | TTable | SelectedFieldsFlat<TColumn>>;\nexport type SelectedFieldsOrdered<TColumn extends Column> = {\n    path: string[];\n    field: TColumn | SQL | SQL.Aliased;\n}[];\n",
